INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_conducao_embriaguez' LIMIT 1), 'Durante fiscalização de trânsito em Campina Grande, agente da STTP constata que o condutor apresenta sinais evidentes de alteração da capacidade psicomotora. O condutor recusa-se a submeter-se ao teste do etilômetro. Considerando o CTB, assinale a alternativa CORRETA:', 'A recusa impede a autuação, pois o teste depende de consentimento livre do condutor.', 'O agente deve aguardar perito criminal antes de lavrar qualquer auto de infração.', 'A recusa em se submeter ao teste constitui infração autônoma prevista no CTB.', 'A infração somente se configura se o etilômetro confirmar concentração acima do limite legal.', NULL, 'C', 'caso_pratico', 'pegadinha_pode_deve', 4, '{"o_que_testa":"Conhecimento sobre embriaguez ao volante e consequência jurídica da recusa ao etilômetro.","fundamento_legal":"CTB, art. 165-A: recusar-se a ser submetido a teste, exame clínico, perícia ou outro procedimento que permita certificar influência de álcool ou outra substância psicoativa, na forma do art. 277, configura infração autônoma de trânsito.","passo_a_passo":["O enunciado descreve sinais de alteração psicomotora + recusa ao etilômetro.","A) Erra: a recusa não impede autuação — é infração autônoma (art. 165-A).","B) Erra: não é necessário aguardar perito para autuação administrativa.","C) Correta: a recusa configura infração autônoma prevista no art. 165-A do CTB.","D) Erra: confunde necessidade de confirmação etílica com a recusa em si."],"pegadinha":"IDECAN troca recusa por necessidade de confirmação etílica — candidato acha que sem teste positivo não há infração.","macete":"Recusou o bafômetro = infração autônoma (art. 165-A). Não precisa estar bêbado no teste.","estudo_reverso":["CTB art. 165","CTB art. 165-A","CTB art. 277"]}'::jsonb, '{"embriaguez","etilometro","recusa"}'::text[]);